/**
 * @method 
 * @name saveCallBack 
 * @description 조회건수/조회총금액, 확인건수/확인총금액 계산
 */
scwin.f_GetConfirmCntTotAmt = function () {
  // 사용료 + 운반비
  let qryCnt = 0,
    qryTotAmt = 0;
  let rowCnt = ds_heavyEquipLoanChargeList.getRowCount();
  if (rowCnt > 0) {
    let colArray = [];
    colArray = ds_heavyEquipLoanChargeList.getColData('hveqLoanAmt');
    const hveqLoanAmt = colArray.reduce((accumulator, currentValue) => {
      return accumulator += $c.num.parseInt($p, currentValue);
    }, 0);
    colArray = ds_heavyEquipLoanChargeList.getColData('prtgCost');
    const prtgCost = colArray.reduce((accumulator, currentValue) => {
      return accumulator += $c.num.parseInt($p, currentValue);
    }, 0);
    qryCnt = rowCnt;
    qryTotAmt = hveqLoanAmt + prtgCost;
  }
  ;
  lay_qryCnt.setValue($c.gus.cfInsertComma($p, qryCnt));
  lay_qryTotAmt.setValue($c.gus.cfInsertComma($p, qryTotAmt));

  // 매입승인구분이 승인(02)인 경우만 사용료 + 운반비 계산
  let confirmCnt = 0,
    confirmTotAmt = 0;
  for (let i = 0; i < rowCnt; i++) {
    let rowData = ds_heavyEquipLoanChargeList.getRowJSON(i);
    if (rowData.copCoConfirmClsCd == "02") {
      confirmTotAmt += $c.num.parseInt($p, rowData.hveqLoanAmt) + $c.num.parseInt($p, rowData.prtgCost);
      confirmCnt++;
    }
    ;
  }
  ;
  lay_confirmCnt.setValue($c.gus.cfInsertComma($p, confirmCnt));
  lay_confirmTotAmt.setValue($c.gus.cfInsertComma($p, confirmTotAmt));
};

